private void processRequireCall(NodeTraversal t, Node n, Node parent) {
    Node left = n.getFirstChild();
    Node arg = left.getNext();

    // Verify that the last argument is a string
    if (verifyLastArgumentIsString(t, left, arg)) {
        String ns = arg.getString();
        ProvidedName provided = providedNames.get(ns);

        // Check if the required module is explicitly provided
        if (provided == null || !provided.isExplicitlyProvided()) {
            // Record unrecognized require
            unrecognizedRequires.add(
                new UnrecognizedRequire(n, ns, t.getSourceName())
            );
        } else {
            JSModule providedModule = provided.explicitModule;

            // Ensure providedModule is non-null due to explicit provide
            Preconditions.checkNotNull(providedModule);

            JSModule module = t.getModule();
            // Check if the current module depends on the provided module
            if (moduleGraph != null &&
                module != providedModule &&
                !moduleGraph.dependsOn(module, providedModule)) {
                compiler.report(
                    t.makeError(n, XMODULE_REQUIRE_ERROR, ns,
                        providedModule.getName(),
                        module.getName())
                );
            }
        }

        // Add nodes to symbol table for further processing
        maybeAddToSymbolTable(left);
        maybeAddStringNodeToSymbolTable(arg);

        // Remove requires before further processing, if necessary
        if (provided != null) {
            parent.detachFromParent();
            compiler.reportCodeChange();
        }
    }
}
```

